#include<bits/stdc++.h>
using namespace std;

int zui[35];
bool jia[35];
int day[10];
int n, m, p, zo[105], me[105], wh[105], to[105];
string name[25];
string xing[7] = {"Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"};
struct node {
	int z = -1, m = 0, w = 0, t = 0;
};
bool panday(int today) {
	bool flag = 0;
	for (int i = 1; i <= 7; i++) if (i != today) if (day[i] != 1) flag = 1;
	return !flag;
}
bool pan(int zong, int me, int who, int today) {
	if (zong == -1) return 1;
	if (zong == 1) {
		if (jia[me] == 1) {
			if (zui[me] != 1) {
				zui[me] = 0;
				return 1;
			} else {
				return 0;
			}
		} else {
			if (zui[me] != 0) {
				zui[me] = 1;
				return 1;
			} else {
				return 0;
			}
		}
	} else if (zong == 2) {
		if (jia[me] == 1) {
			if (zui[me] != 0) {
				zui[me] = 1;
				return 1;
			} else {
				return 0;
			}
		} else {
			if (zui[me] != 1) {
				zui[me] = 0;
				return 1;
			} else {
				return 0;
			}
		}
	} else if (zong == 3) {
		if (jia[me] == 1) {
			if (zui[who] != 1) {
				zui[who] = 0;
				return 1;
			} else {
				return 0;
			}
		} else {
			if (zui[who] != 0) {
				zui[who] = 1;
				return 1;
			} else {
				return 0;
			}
		}
	} else if (zong == 4) {
		if (jia[me] == 1) {
			if (zui[who] != 0) {
				zui[who] = 1;
				return 1;
			} else {
				return 0;
			}
		} else {
			if (zui[who] != 1) {
				zui[who] = 0;
				return 1;
			} else {
				return 0;
			}
		}
	}  else {
		if (jia[me] == 0) {
			if (day[today]) {
				return 0;
			} else {
				for (int i = 1; i <= 7; i++) day[i] = 1;
				day[today] = 0;
				return 1;
			}
		} else {
			if (panday(today)) {
				return 0;
			} else {
				day[today] = 1;
				return 1;
			}
		}
	}
}
node chu(string a) {
	int ii = 0;
	string b, c;
	b.clear();
	for (; a[ii] != ':'; ii++) b += a[ii];
	ii++;
	ii++;
	for (; a[ii] != ' '; ii++) c += a[ii];
	if (c == "I") {
		string d;
		for (; ii < a.size(); ii++) d += a[ii];
		if (d == " am guilty.") {
			for (int i = 1; i <= m; i++) {
				if (b == name[i]) {
					node temp;
					temp.m = i;
					temp.z = 1;
					return temp;
				}
			}
		} else if (d == " am not guilty.") {
			for (int i = 1; i <= m; i++) {
				if (b == name[i]) {
					node temp;
					temp.m = i;
					temp.z = 2;
					return temp;
				}
			}
		}
		node temp;
		temp.z = -1;
		return temp;
	} else if (c == "Today") {
		string d;
		for (; ii < a.size(); ii++) d += a[ii];
		for (int i = 0; i < 7; i++) {
			string bb = " is " + xing[i] + '.';
			if (d == bb) {
				for (int j = 1; j <= m; j++) {
					if (b == name[j]) {
						node temp;
						temp.m = j;
						temp.z = 5;
						temp.t = i + 1;
						return temp;
					}
				}
			}
		}
		node temp;
		temp.z = -1;
		return temp;
	} else {
		for (int i = 1; i <= m; i++) {
			if (c == name[i]) {
				string d;
				for (; ii < a.size(); ii++) d += a[ii];
				for (int j = 1; j <= m; j++) {
					if (b == name[j]) {
						if (d == " is guilty.") {
							node temp;
							temp.w = i;
							temp.z = 3;
							temp.m = j;
							return temp;
						} else if (d == " is not guilty.") {
							node temp;
							temp.w = i;
							temp.z = 4;
							temp.m = j;
							return temp;
						}
					}
				}

			}
		}
		node temp;
		temp.z = -1;
		return temp;
	}
	node temp;
	temp.z = -1;
	return temp;
}

void in() {
	cin >> m >> n >> p;
	for (int i = 1; i <= m; i++) {
		cin >> name[i];
	}
	string hhh;
	getline(cin, hhh);
	for (int j = 1; j <= p; j++) {
		string a;
		getline(cin, a);
		string b;
		for (int i = 0; a[i] != '\r' && i < a.size(); i++) b += a[i];
		node temp = chu(b);
		zo[j] = temp.z;
		me[j] = temp.m;
		wh[j] = temp.w;
		to[j] = temp.t;
	}
	return;
}
int solve() {
	for (int i = 1; i <= p; i++) {
		if (!pan(zo[i], me[i], wh[i], to[i])) {
			return -3;
		}
	}
	int ans = 0;
	for (int i = 1; i <= m; i++) {
		if (zui[i] == 1) {
			ans++;
		}
	}
	if (ans >= 2) return -1;
	if (ans == 0) {
		ans = 0;
		int ans2 = 0;
		for (int i = 1; i <= m; i++) {
			if (zui[i] == -1) {
				ans++;
			} else if (zui[i] == 0) {
				ans2++;
			}
		}
		if (ans == 1 && ans2 == m - 1) {
			for (int i = 1; i <= m; i++) {
				if (zui[i] == -1) {
					return i;
				}
			}
		}
		ans = 0;
		for (int i = 1; i <= m; i++) {
			if (zui[i] == -1) {
				ans++;
			}
		}
		if(ans>=1){
			return -1;
		}
		return -2;
	}
	for (int i = 1; i <= m; i++) {
		if (zui[i] == 1) {
			return i;
		}
	}
	return 0;
}
int mei(int x, int y) {
	if (x > n) return -4;
	if (x == n && y > m) {
		for (int i = 1; i <= m; i++) zui[i] = -1;
		for (int i = 1; i <= 7; i++) day[i] = 0;
		int ans = solve();
		return ans;
	}
	if (y > m) return -5;
	int ans = -10;
	if (x < n) {
		jia[y] = 1;
		ans = mei(x + 1, y + 1);
	}
	jia[y] = 0;
	ans = max(ans, mei(x, y + 1));
	return ans;
}
int main() {
	in();
	int ans = mei(0, 1);
	if (ans >= 1) {
		cout << name[ans];
	} else if (ans == -1) {
		cout << "Cannot Determine";
	} else {
		cout << "Impossible";
	}
	return 0;
}
